import React, { useState } from 'react'
import Typography from '@material-ui/core/Typography'
import Button from '@material-ui/core/Button'
import Container from '@material-ui/core/Container'
import { makeStyles } from '@material-ui/core'
import TextField from '@material-ui/core/TextField'
// import { useHistory } from 'react-router-dom'

const useStyles = makeStyles({
  field: {
    marginTop: 20,
    marginBottom: 20,
    display: 'block'
  }
})

export default function CreateClassroom() {
  const classes = useStyles()
//   const history = useHistory()
  const [title, setTitle] = useState('')
  const [titleError, setTitleError] = useState('')
  const [instructor, setInstructor] = useState('')
  const [instructorError, setInstructorError] = useState('')
  const [yearSection, setYearSection] = useState('')
  const [yearSectionError, setYearSectionError] = useState('')

  const [data, setData] = useState({
    title: '',
    instructor: '',
    yearSection: ''
})

const handleChange = (event) => {
    const name = event.target.name;
    const value = event.target.value;

    setData(data => ({...data, [name]: value}));
}

  const handleSubmit = (e) => {
    e.preventDefault()
    setTitleError(false)
    setInstructorError(false)
    setYearSectionError(false)
    

    if (title == '') {
      setTitleError('Incorrect input')
    }
    
    if (instructor == '') {
        setInstructorError('Incorrect input')
    }

    if (yearSection == '') {
        setYearSectionError('Incorrect input')
    }
    console.log(title, instructor, yearSection);
    // if (title && details) {
    //   fetch('http://localhost:8000/notes', {
    //     method: 'POST',
    //     headers: {"Content-type": "application/json"},
    //     body: JSON.stringify({ title, details, category })
    //   }).then(() => history.push('/'))
    // } 
  }

  return (
    <>
    <Container size="md">
      <Typography
        variant="h6" 
        color="textSecondary"
        component="h2"
        gutterBottom
      >
        Create a classroom
      </Typography>
      
      <form noValidate autoComplete="off" onSubmit={handleSubmit}>
        <TextField className={classes.field}
          onChange={handleChange}
          value={data.title}
          label="Class name" 
          variant="outlined" 
          color="secondary" 
          fullWidth
          required
          helperText={titleError}
        />
        <TextField className={classes.field}
          onChange={handleChange}
          value={data.instructor}
          label="Instructor" 
          variant="outlined" 
          color="secondary" 
          fullWidth
          required
          helperText={instructorError}
        />
        <TextField className={classes.field}
          onChange={handleChange}
          value={data.yearSection}
          label="Year&Section" 
          variant="outlined" 
          color="secondary" 
          fullWidth
          required
          helperText={yearSectionError}
        />


        <Button
          type="submit" 
          color="secondary" 
          variant="contained"
          fullWidth>
          Create
        </Button>
      </form>

      
    </Container>
    </>
  )
}
